class Solution {
    public int longestSemiRepetitiveSubstring(String s) {
        int n = s.length();
        int res = 0;
        for (int i = 0; i < n; i++) {
            int count = 1;
            for (int j = i + 2; j < n; j += 2) {
                if (s.charAt(j) == s.charAt(j - 1) && s.charAt(j) == s.charAt(j - 2)) {
                    break;
                }
                if (s.charAt(j) == s.charAt(j - 1)) {
                    count++;
                }
            }
            res = Math.max(res, count);
        }
        return res;
    }
}
